param([string]$IncomingRoot,[string]$RunId,[ValidateSet('GDAXI','AUDCAD')][string]$Symbol='GDAXI')
$ErrorActionPreference='Stop';$target='execution';$csvName='nora_phase2_execution_tester_v1.csv';$complete='NORA_PHASE2_EXECUTION_COMPLETE_V1';$fail='NORA_PHASE2_EXECUTION_FAIL';$terminal='C:\Program Files\Darwinex MetaTrader 5\terminal64.exe';$root=Join-Path $env:USERPROFILE 'NoraPhase2ExecutionValidation\evidence-v1';$run=Join-Path $root $RunId
if(Test-Path $run){throw 'occupied run destination'};New-Item -ItemType Directory $run|Out-Null
function H($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()}
try{$data=Get-ChildItem "$env:APPDATA\MetaQuotes\Terminal" -Directory|?{(Test-Path (Join-Path $_.FullName 'origin.txt')) -and ((Get-Content (Join-Path $_.FullName 'origin.txt') -Raw).Trim() -eq 'C:\Program Files\Darwinex MetaTrader 5')}|select -First 1 -Expand FullName;if(!$data){throw 'Darwinex data root absent'};if(Get-Process terminal64 -ErrorAction SilentlyContinue){throw 'conflicting terminal'};$src=Join-Path $IncomingRoot 'generated\phase2_execution';$ex5=Join-Path $src 'NoraPhase2ExecutionTesterCanaryV1.ex5';if(!(Test-Path $ex5)){throw 'missing current EX5'};$expertDir=Join-Path $data 'MQL5\Experts\NoraPhase2Execution';New-Item -ItemType Directory -Force $expertDir|Out-Null;Copy-Item $ex5 (Join-Path $expertDir 'NoraPhase2ExecutionTesterCanaryV1.ex5') -Force;$common=Join-Path (Split-Path $data -Parent) 'Common\Files';$commonCsv=Join-Path $common $csvName;if(Test-Path $commonCsv){Remove-Item $commonCsv -Force};$journal=Join-Path $data 'Tester\logs\'+(Get-Date -Format yyyyMMdd)+'.log';$before=if(Test-Path $journal){(Get-Item $journal).Length}else{0};$ini=Get-Content 'C:\Program Files\Darwinex MetaTrader 5\backtest_run.ini' -Raw;$ini=[regex]::Replace($ini,'(?m)^Expert=.*$','Expert=NoraPhase2Execution\NoraPhase2ExecutionTesterCanaryV1');$ini=[regex]::Replace($ini,'(?m)^Symbol=.*$',('Symbol='+$Symbol));$ini=[regex]::Replace($ini,'(?m)^Period=.*$','Period=M1');$ini=[regex]::Replace($ini,'(?m)^Report=.*$',('Report='+(Join-Path $run 'tester.htm')));$ini=[regex]::Replace($ini,'(?m)^ReplaceReport=.*$','ReplaceReport=1');Set-Content (Join-Path $run 'tester.ini') $ini -Encoding ascii;$start=(Get-Date).ToUniversalTime();$p=Start-Process $terminal -ArgumentList ('/config:"'+(Join-Path $run 'tester.ini')+'"') -PassThru;if(!$p.WaitForExit(120000)){throw 'tester timeout'};$end=(Get-Date).ToUniversalTime();if(!(Test-Path $commonCsv)){throw 'missing fresh csv'};Copy-Item $commonCsv (Join-Path $run $csvName);$segment=if(Test-Path $journal){$fs=[IO.File]::OpenRead($journal);$fs.Seek($before,[IO.SeekOrigin]::Begin)|Out-Null;$sr=New-Object IO.StreamReader($fs);$x=$sr.ReadToEnd();$sr.Close();$x}else{''};$segment|Set-Content (Join-Path $run 'tester-journal.log') -Encoding utf8;$completion=$segment -match [regex]::Escape($complete);$failure=$segment -match [regex]::Escape($fail);if(!$completion -or $failure){throw 'marker state failed'};$report=Join-Path $run 'tester.htm';if(!(Test-Path $report)){@{schema_version='nora.phase2.execution_tester_evidence_v1';run_identifier=$RunId;symbol=$Symbol;timeframe='M1';start_utc=$start.ToString('o');completion_utc=$end.ToString('o');ex5_sha256=(H $ex5);csv_sha256=(H (Join-Path $run $csvName));journal_sha256=(H (Join-Path $run 'tester-journal.log'));completion_marker_present=$completion;failure_marker_present=$failure;substitute='native journal-bounded tester evidence'}|ConvertTo-Json -Depth 5|Set-Content $report -Encoding utf8};@{run_identifier=$RunId;target_identifier=$target;host_symbol=$Symbol;timeframe='M1';requested_start_utc=$start.ToString('o');observed_completion_utc=$end.ToString('o');ex5_path=$ex5;ex5_sha256=(H $ex5);ex5_size=(Get-Item $ex5).Length;tester_configuration_sha256=(H (Join-Path $run 'tester.ini'));result_csv_sha256=(H (Join-Path $run $csvName));journal_source=$journal;journal_baseline_bytes=$before;journal_segment_sha256=(H (Join-Path $run 'tester-journal.log'));completion_marker_present=$completion;failure_marker_present=$failure;process_exit=$p.ExitCode;collection_state='complete'}|ConvertTo-Json -Depth 5|Set-Content (Join-Path $run 'execution.json') -Encoding utf8}catch{@{run_identifier=$RunId;collection_state='failed';failure=$_.Exception.Message}|ConvertTo-Json|Set-Content (Join-Path $run 'execution.json') -Encoding utf8;throw}
